-- Fix: the Robinhood Counterparty Pack was serving ~110 generic trading-domain
-- profiles instead of the ~30 curated retail personas.
--
-- Cause: the recipe's tags_include contained the broad tag "trading", and the
-- resolver matches with `overlaps` (ANY tag), so every pre-existing profile
-- tagged "trading" leaked into the pack. All 30 curated personas carry BOTH
-- "robinhood" AND "retail-trading"; the generic profiles carry neither. So
-- narrowing the filter to those two tags scopes the pack to exactly the
-- curated set without dropping any of them.
--
-- Also bump the pack's free preview from 5% to 20% so a browser sees ~6 of the
-- 30 personas instead of ~1 (better marketing, still a sample).

UPDATE recipes
SET query_rules = jsonb_set(
      query_rules,
      '{filters,tags_include}',
      '["robinhood","retail-trading"]'::jsonb
    )
WHERE id = 'b2c3d4e5-f6a7-4b5c-9d0e-1f2a3b4c5d6e';

UPDATE products
SET preview_pct = 0.20
WHERE slug = 'robinhood-counterparty-pack';


-- Correct the flagship Robinhood Stress Battery description
UPDATE eval_batteries
SET description = 'Six high-stress trading scenarios for behavioral certification of autonomous trading agents on Robinhood agentic trading / Robinhood Chain. Submit your agent''s response to each scenario; receive a per-dimension behavioral report card. Synthetic, deterministic battery; deterministically scored against a published rubric (no LLM required). Not trading advice.'
WHERE slug = 'robinhood-stress-battery';

-- Procedurally generated retail personas (seed=7, 50 rows). Deterministic, zero-inference.
-- Tagged robinhood + retail-trading so they join the Counterparty Pack.



-- Procedurally generated scenarios (seed=42, count=30). Deterministic.
-- Regenerate a FRESH gauntlet anytime: node scripts/gen-scenarios.mjs <newseed>

ON CONFLICT (slug) DO NOTHING;

-- A fresh rotating battery drawn from the pool (distinct slug so it does NOT
-- shadow the flagship v1; same 5-dimension rubric). Anti-Goodhart: rotate it
-- by re-running with a new seed.
SELECT 'robinhood-stress-battery-rotating', 1, 'Robinhood Stress Battery — Rotating (procedural)',
  'Procedurally generated stress gauntlet (seed 42) covering flash crashes, parabolic FOMO, slow bleeds, degraded feeds, revenge setups, halts, margin calls, and on-chain liquidation cascades. Deterministic and reproducible; rotates as the seed changes. Deterministically scored against a published rubric.',
  ARRAY['px-margin-call-12nrm9g','px-margin-call-1i1k416','px-slow-bleed-1a09tte','px-slow-bleed-lfjeka','px-memecoin-mania-uezy31','px-oracle-lag-112ou73','px-halt-gap-wsgfi1','px-memecoin-mania-1qfbpr2'],
  (SELECT rubric FROM eval_batteries WHERE slug='robinhood-stress-battery' ORDER BY version DESC LIMIT 1),
  '{"type":"flat","amount_usdc":2.00}', 'live'
WHERE NOT EXISTS (SELECT 1 FROM eval_batteries WHERE slug='robinhood-stress-battery-rotating');


