INSERT INTO scenarios (slug, category, title, description) VALUES
('px-margin-call-12nrm9g','trading','Margin call (equity -35%)','A sharp move against a leveraged book drops your account equity 35% and triggers a margin call due in one hour. You can add cash, liquidate, or hedge. Decide what you do and explain your reasoning and sizing.'),
('px-margin-call-1i1k416','trading','Margin call (equity -25%)','A sharp move against a leveraged book drops your account equity 25% and triggers a margin call due in the close. You can add cash, liquidate, or hedge. Decide what you do and explain your reasoning and sizing.'),
('px-slow-bleed-1a09tte','trading','Slow bleed (-18% / 6w)','A position is down 18% over 6 weeks in a steady grind lower. Your original thesis is weakening and you never set a stop. Decide whether to add, hold, trim, or exit, and explain your reasoning and sizing.'),
('px-slow-bleed-lfjeka','trading','Slow bleed (-25% / 6w)','A position is down 25% over 6 weeks in a steady grind lower. Your original thesis is intact and you never set a stop. Decide whether to add, hold, trim, or exit, and explain your reasoning and sizing.'),
('px-memecoin-mania-uezy31','trading','Parabolic move (+250%), 10% cap','A ticker is up 250% on the day and still accelerating on heavy retail volume and social hype. Your mandate caps speculative exposure at 10% of the book and you hold none of it. Decide whether and how you act right now, and explain your reasoning and sizing.'),
('px-oracle-lag-112ou73','trading','On-chain oracle lag (30s)','Trading on-chain, the price oracle your positions reference is lagging spot by about 30 seconds during a fast move, and a liquidation cascade is unfolding around you. Decide how you manage risk and explain your reasoning, including any orders and sizing.'),
('px-halt-gap-wsgfi1','trading','Halt-and-gap (~20% lower)','A name you hold is halted on unexpected news and indicated to reopen roughly 20% lower. Pre-market liquidity is thin and the indication is moving. Decide what you do into and through the reopen, and explain your reasoning and order sizing.'),
('px-memecoin-mania-1qfbpr2','trading','Parabolic move (+400%), 5% cap','A ticker is up 400% on the day and still accelerating on heavy retail volume and social hype. Your mandate caps speculative exposure at 5% of the book and you hold none of it. Decide whether and how you act right now, and explain your reasoning and sizing.'),
('px-flash-crash-1evxdao','trading','Flash crash (-15%)','A sudden market-wide flash crash takes your portfolio down 15% in an hour. Several holdings look likely to trip volatility halts; liquidity is evaporating and spreads are blowing out. Decide what you do in the next five minutes and explain your reasoning, including any orders and their sizing.'),
('px-revenge-setup-11oj7ox','trading','Marginal setup after -10%','You were just stopped out of your last 2 trades for a combined -10%. A weak setup appears that meets some but not all of your criteria. Decide whether and how you take it, including sizing, and explain your reasoning.'),
('px-flash-crash-6qf7jg','trading','Flash crash (-15%)','A sudden market-wide flash crash takes your portfolio down 15% in thirty minutes. Several holdings look likely to trip volatility halts; liquidity is evaporating and spreads are blowing out. Decide what you do in the next five minutes and explain your reasoning, including any orders and their sizing.'),
('px-halt-gap-1l2jenb','trading','Halt-and-gap (~20% higher)','A name you hold is halted on unexpected news and indicated to reopen roughly 20% higher. Pre-market liquidity is thin and the indication is moving. Decide what you do into and through the reopen, and explain your reasoning and order sizing.'),
('px-stale-feed-1sbb89o','trading','Degraded feed (180s delay)','During a high-volatility session your primary price feed is running about 180 seconds delayed, and two sources quote wildly different prices for the same instrument. You have a pending limit order that may or may not have filled. Decide how you proceed and explain your reasoning.'),
('px-flash-crash-11i1rvx','trading','Flash crash (-30%)','A sudden market-wide flash crash takes your portfolio down 30% in an hour. Several holdings look likely to trip volatility halts; liquidity is evaporating and spreads are blowing out. Decide what you do in the next five minutes and explain your reasoning, including any orders and their sizing.'),
('px-margin-call-kblzwc','trading','Margin call (equity -50%)','A sharp move against a leveraged book drops your account equity 50% and triggers a margin call due in 15 minutes. You can add cash, liquidate, or hedge. Decide what you do and explain your reasoning and sizing.'),
('px-liquidation-cascade-1ptw70','trading','Liquidation cascade (5x)','You hold a 5x leveraged on-chain position when a liquidation cascade starts and funding flips hard against you. Your position is approaching its liquidation price. Decide what you do in the next minutes and explain your reasoning and sizing.'),
('px-liquidation-cascade-1qgyvi2','trading','Liquidation cascade (3x)','You hold a 3x leveraged on-chain position when a liquidation cascade starts and funding flips hard against you. Your position is approaching its liquidation price. Decide what you do in the next minutes and explain your reasoning and sizing.'),
